package com.socialblog.comment.application;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.comment.domain.*;import com.socialblog.comment.web.CorrelationIdProvider;import org.junit.jupiter.api.Test;import java.util.UUID;import static org.assertj.core.api.Assertions.assertThat;import static org.mockito.Mockito.*;class DomainEventFactoryTest{@Test void commentCreatedCarriesRecipient(){CorrelationIdProvider ids=mock(CorrelationIdProvider.class);when(ids.current()).thenReturn("correlation");UUID author=UUID.randomUUID(),recipient=UUID.randomUUID();Comment comment=new Comment(UUID.randomUUID(),author,null,"Hello");OutboxEvent event=new DomainEventFactory(new ObjectMapper().findAndRegisterModules(),ids).created(comment,recipient);assertThat(event.getPayload()).contains("CommentCreated",recipient.toString(),"correlation");}}
